#include<bits/stdc++.h>
using namespace std;
struct node
{
    int m,v,d,id;
    bool operator<(const node&b)const
    {
        return d<b.d;
    }
}e[200010];
int n,m,tot,pos[100010],a[100010],s[100010];
long long ans[100010];
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
int query(int x)
{
    int sum=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        sum+=s[i];
    }
    return sum;
}
void cdq(int l,int r)
{
    if(l==r)
    {
        return;
    }
    int mid=(l+r)>>1;
    cdq(l,mid);
    cdq(mid+1,r);
    sort(e+l,e+1+mid);
    sort(e+1+mid,e+1+r);
    int j=l;
    for(int i=mid+1;i<=r;i++)
    {
        while(j<=mid&&e[j].d<=e[i].d)
        {
            add(e[j].v,e[j].m);
            j++;
        }
        ans[e[i].id]+=e[i].m*(query(n)-query(e[i].v));
    }
    for(int i=l;i<j;i++)
    {
        add(e[i].v,-e[i].m);
    }
    j=mid;
    for(int i=r;i>mid;i--)
    {
        while(j>=l&&e[j].d>=e[i].d)
        {
            add(e[j].v,e[j].m);
            j--;
        }
        ans[e[i].id]+=e[i].m*query(e[i].v-1);
    }
    for(int i=mid;i>j;i--)
    {
        add(e[i].v,-e[i].m);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        pos[a[i]]=i;
        e[++tot]=(node){1,a[i],i,0};
    }
    for(int i=1;i<=m;i++)
    {
        int x;
        scanf("%d",&x);
        e[++tot]=(node){-1,x,pos[x],i};
    }
    cdq(1,tot);
    for(int i=1;i<=m;i++)
    {
        ans[i]+=ans[i-1];
    }
    for(int i=0;i<m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
